args.cypher:
// Search for FacilityInformation submodels
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept {id: 'https://admin-shell.io/dfki/SubmodelTemplate/FacilityInformation/1/0'})
RETURN aas.idShort, sm.idShort, aas.id

// Search all submodels for AssetLocation template
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept {id: 'https://admin-shell.io/idta/smt/assetlocation/1/0'})
RETURN aas.idShort, sm.idShort, aas.id

// List all submodels for each AGV instance
MATCH (instanceAas:AssetAdministrationShell {idShort: 'MiR100_001'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN 'MiR100_001' AS aas, sm.idShort

// List all submodels for MiR250_001
MATCH (instanceAas:AssetAdministrationShell {idShort: 'MiR250_001'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN 'MiR250_001' AS aas, sm.idShort

// List all submodels for MiR250_002
MATCH (instanceAas:AssetAdministrationShell {idShort: 'MiR250_002'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN 'MiR250_002' AS aas, sm.idShort

// List all submodels for AGV type shells
MATCH (typeAas:AssetAdministrationShell {idShort: 'MiR100_Type'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN 'MiR100_Type' AS aas, sm.idShort

// List all submodels for MiR250_Type
MATCH (typeAas:AssetAdministrationShell {idShort: 'MiR250_Type'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN 'MiR250_Type' AS aas, sm.idShort

// Check all AAS shells to see if any have location-related semanticIds
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
RETURN DISTINCT sc.id

// Check UR20_001 submodels
MATCH (aas:AssetAdministrationShell {idShort: 'UR20_001'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN aas.idShort, sm.idShort

// Check UR3e_001 submodels
MATCH (aas:AssetAdministrationShell {idShort: 'UR3e_001'})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN aas.idShort, sm.idShort
